use anyhow::{Context, Result};
use serde_json::json;
use std::fs;
use std::path::Path;

use crate::output;

const BEGIN_MARKER: &str = "BEGIN MONDAYBOT INTEGRATION";
const END_MARKER: &str = "END MONDAYBOT INTEGRATION";

const AGENTS_CONTENT: &str = r#"### Monday.com Sync (mondaybot)
<!-- Auto-generated by 'mondaybot setup agents' - do not remove these markers -->
<!-- BEGIN MONDAYBOT INTEGRATION -->

This project uses **mondaybot** to sync beads issues with monday.com.

#### Key Principle: Sync is Opt-In
- Only **explicitly linked** issues sync between beads and monday.com
- Running `mondaybot sync update` is always safe — it never creates items, only refreshes linked ones
- Use `mondaybot sync push <beads-id>` to selectively push a beads issue to monday
- Use `mondaybot link add <beads-id> <monday-item-id>` to tie existing items together

#### Quick Reference
```bash
mondaybot doctor                                  # Check setup health
mondaybot boards list                             # List available boards
mondaybot boards get --board-id <id>              # Show board columns/groups (useful for setup)

mondaybot items list                              # List items on configured board
mondaybot items get --item-id <id>                # Get item with sub-items
mondaybot items create --name "Task title"        # Create item on board
mondaybot subitems create --parent-id <id> --name "Sub-task"

mondaybot link add <beads-id> <monday-item-id>    # Link a beads issue to a monday item
mondaybot link list                               # Show all links
mondaybot link remove <beads-id>                  # Unlink

mondaybot sync push <beads-id>                    # Push one issue to monday (creates if new)
mondaybot sync push --epic <beads-id>             # Push epic + child tasks
mondaybot sync pull <monday-item-id>              # Pull one item into beads (creates if new)
mondaybot sync update                             # Refresh all linked items (safe, no creates)
mondaybot sync status                             # Show what's linked and what's drifted
```

#### Workflow
1. PM creates a task in monday.com (or you create one with `mondaybot items create`)
2. Create a matching beads epic: `bd create "Epic title" -t epic`
3. Link them: `mondaybot link add <beads-id> <monday-item-id>`
4. Work on sub-tasks in beads: `bd create "Sub-task" --parent <epic-id>`
5. Push sub-tasks that matter: `mondaybot sync push <sub-task-beads-id>`
6. Keep linked items fresh: `mondaybot sync update`
7. Check drift: `mondaybot sync status`

#### What NOT to do
- Do NOT run a bulk sync of all beads issues — most are internal dev tasks
- Do NOT manually edit `.beads/monday_sync.json` (managed by mondaybot, committed to git)
- Only push issues to monday that are relevant to project tracking

All mondaybot commands output JSON to stdout for programmatic use.

<!-- END MONDAYBOT INTEGRATION -->"#;

