/// Insert or replace content between markers in existing text.
/// Returns (new_content, was_replaced).
fn upsert_between_markers(existing: &str, section: &str, begin: &str, end: &str) -> (String, bool) {
    if let (Some(start_idx), Some(end_idx)) = (existing.find(begin), existing.find(end)) {
        let end_of_end = end_idx + existing[end_idx..].find('\n').unwrap_or(end.len());
        let mut result = String::new();
        // Find the start of the line containing BEGIN marker
        let line_start = existing[..start_idx].rfind('\n').map_or(0, |i| i + 1);
        result.push_str(&existing[..line_start]);
        result.push_str(section);
        if !section.ends_with('\n') {
            result.push('\n');
        }
        result.push_str(&existing[end_of_end..]);
        (result, true)
    } else {
        let mut result = existing.to_string();
        if !result.is_empty() && !result.ends_with('\n') {
            result.push('\n');
        }
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(section);
        if !result.ends_with('\n') {
            result.push('\n');
        }
        (result, false)
    }
}

pub fn write_agents(dir: &Path) -> Result<()> {
    fs::create_dir_all(dir)
        .with_context(|| format!("failed to create {}", dir.display()))?;
    let file_path = dir.join("AGENTS.md");
    let existing = if file_path.exists() {
        fs::read_to_string(&file_path)
            .with_context(|| format!("failed to read {}", file_path.display()))?
    } else {
        String::new()
    };

    let (new_content, replaced) = upsert_between_markers(
        &existing,
        AGENTS_CONTENT,
        BEGIN_MARKER,
        END_MARKER,
    );

    fs::write(&file_path, &new_content)
        .with_context(|| format!("failed to write {}", file_path.display()))?;

    let action = if replaced {
        "updated"
    } else if existing.is_empty() {
        "created"
    } else {
        "appended"
    };

    output::success(&json!({
        "file": file_path.display().to_string(),
        "action": action,
    }))
}

pub fn write_cursor(dir: &Path) -> Result<()> {
    let cursor_dir = dir.join(".cursor").join("rules");
    fs::create_dir_all(&cursor_dir)
        .with_context(|| format!("failed to create {}", cursor_dir.display()))?;

    let file_path = cursor_dir.join("mondaybot.mdc");
    let existing = if file_path.exists() {
        fs::read_to_string(&file_path)
            .with_context(|| format!("failed to read {}", file_path.display()))?
    } else {
        String::new()
    };

    let (new_content, replaced) = upsert_between_markers(
        &existing,
        CURSOR_CONTENT,
        BEGIN_MARKER,
        END_MARKER,
    );

    fs::write(&file_path, &new_content)
        .with_context(|| format!("failed to write {}", file_path.display()))?;

    let action = if replaced {
        "updated"
    } else if existing.is_empty() {
        "created"
    } else {
        "appended"
    };

    output::success(&json!({
        "file": file_path.display().to_string(),
        "action": action,
    }))
}
